Windows内核中IOCTL（Input/Output Control）通信是用户态程序与内核驱动交互的核心机制。当用户态调用DeviceIoControl时，系统会创建一个IRP（I/O Request Packet），并将其发送到目标驱动设备的派遣函数（通常为MajorFunction 0x0e即IRP_MJ_DEVICE_CONTROL）。驱动在Dispatch函数中通过IoGetCurrentIrpStackLocation获取IOCTL码和输入/输出缓冲区，然后处理请求并设置Irp->IoStatus.Status和Information，最后调用IoCompleteRequest返回用户态。

以下是一个简单的驱动示例，注册一个设备并处理IOCTL 0x222000（自定义码），实现从用户态接收数据并回显：

c
#include <ntddk.h>
#define IOCTL_ECHO CTL_CODE(FILE_DEVICE_UNKNOWN, 0x800, METHOD_BUFFERED, FILE_ANY_ACCESS)

NTSTATUS DriverEntry(PDRIVER_OBJECT DriverObject, PUNICODE_STRING RegistryPath) {
    UNICODE_STRING devName = RTL_CONSTANT_STRING(L"\\Device\\MyDevice");
    UNICODE_STRING symLink = RTL_CONSTANT_STRING(L"\\??\\MyDevice");
    PDEVICE_OBJECT DeviceObject = NULL;
    NTSTATUS status = IoCreateDevice(DriverObject, 0, &devName, FILE_DEVICE_UNKNOWN, 0, FALSE, &DeviceObject);
    if (!NT_SUCCESS(status)) return status;
    status = IoCreateSymbolicLink(&symLink, &devName);
    if (!NT_SUCCESS(status)) { IoDeleteDevice(DeviceObject); return status; }
    DriverObject->MajorFunction[IRP_MJ_CREATE] = DriverObject->MajorFunction[IRP_MJ_CLOSE] = DispatchCreateClose;
    DriverObject->MajorFunction[IRP_MJ_DEVICE_CONTROL] = DispatchIoctl;
    return STATUS_SUCCESS;
}

NTSTATUS DispatchCreateClose(PDEVICE_OBJECT DeviceObject, PIRP Irp) {
    Irp->IoStatus.Status = STATUS_SUCCESS;
    Irp->IoStatus.Information = 0;
    IoCompleteRequest(Irp, IO_NO_INCREMENT);
    return STATUS_SUCCESS;
}

NTSTATUS DispatchIoctl(PDEVICE_OBJECT DeviceObject, PIRP Irp) {
    PIO_STACK_LOCATION stack = IoGetCurrentIrpStackLocation(Irp);
    NTSTATUS status = STATUS_INVALID_DEVICE_REQUEST;
    ULONG info = 0;
    if (stack->Parameters.DeviceIoControl.IoControlCode == IOCTL_ECHO) {
        PVOID inBuf = Irp->AssociatedIrp.SystemBuffer;
        ULONG inLen = stack->Parameters.DeviceIoControl.InputBufferLength;
        PVOID outBuf = Irp->AssociatedIrp.SystemBuffer; // METHOD_BUFFERED
        ULONG outLen = stack->Parameters.DeviceIoControl.OutputBufferLength;
        if (inLen > 0 && outLen >= inLen) {
            RtlCopyMemory(outBuf, inBuf, inLen);
            info = inLen;
            status = STATUS_SUCCESS;
        } else status = STATUS_BUFFER_TOO_SMALL;
    }
    Irp->IoStatus.Status = status;
    Irp->IoStatus.Information = info;
    IoCompleteRequest(Irp, IO_NO_INCREMENT);
    return status;
}


