NTSTATUS DrvDispatch(DEVICE_OBJECT *devobj, IRP *irp) {
    PIO_STACK_LOCATION irpStack = IoGetCurrentIrpStackLocation(irp);
    ULONG ioctlCode = irpStack->Parameters.DeviceIoControl.IoControlCode;
    PVOID inputBuf = irp->AssociatedIrp.SystemBuffer;
    ULONG inputLen = irpStack->Parameters.DeviceIoControl.InputBufferLength;
    ULONG outputLen = irpStack->Parameters.DeviceIoControl.OutputBufferLength;
    NTSTATUS status = STATUS_SUCCESS;
    ULONG info = 0;
    switch (ioctlCode) {
        case IOCTL_TEST: {
            // 假设IOCTL使用METHOD_BUFFERED
            if (inputLen < sizeof(ULONG) || outputLen < sizeof(ULONG)) {
                status = STATUS_BUFFER_TOO_SMALL;
                break;
            }
            ULONG userValue = *(PULONG)inputBuf;
            *(PULONG)irp->AssociatedIrp.SystemBuffer = userValue * 2;
            info = sizeof(ULONG);
            break;
        }
        default:
            status = STATUS_INVALID_DEVICE_REQUEST;
    }
    irp->IoStatus.Status = status;
    irp->IoStatus.Information = info;
    IoCompleteRequest(irp, IO_NO_INCREMENT);
    return status;
}


