Windows内核中IOCTL（Input/Output Control）通信是用户态程序与内核驱动交互的核心机制。用户态通过CreateFile打开设备对象（如\\.\HackSysExtremeVulnerableDriver），然后调用DeviceIoControl发送控制码（IOCTL code）和输入/输出缓冲区。驱动在Dispatch函数中根据IOCTL code执行相应操作。IOCTL code由CTL_CODE宏定义，包含设备类型、功能码、访问权限等。驱动需注册IRP_MJ_DEVICE_CONTROL处理函数。以下是一个简单驱动示例，处理两个IOCTL：读取内核地址和写入内核地址。注意：实际驱动需处理同步、缓冲区检查等。代码使用WDK风格。

c
#include <ntddk.h>
#define IOCTL_READ_MEM CTL_CODE(FILE_DEVICE_UNKNOWN, 0x800, METHOD_BUFFERED, FILE_ANY_ACCESS)
#define IOCTL_WRITE_MEM CTL_CODE(FILE_DEVICE_UNKNOWN, 0x801, METHOD_BUFFERED, FILE_ANY_ACCESS)

NTSTATUS DriverDispatch(PDEVICE_OBJECT DeviceObject, PIRP Irp) {
    PIO_STACK_LOCATION stack = IoGetCurrentIrpStackLocation(Irp);
    ULONG ioctlCode = stack->Parameters.DeviceIoControl.IoControlCode;
    PVOID inputBuffer = stack->Parameters.DeviceIoControl.Type3InputBuffer;
    PVOID outputBuffer = Irp->UserBuffer;
    ULONG inputLen = stack->Parameters.DeviceIoControl.InputBufferLength;
    ULONG outputLen = stack->Parameters.DeviceIoControl.OutputBufferLength;
    NTSTATUS status = STATUS_SUCCESS;
    ULONG_PTR addr;
    ULONG value;

    switch (ioctlCode) {
        case IOCTL_READ_MEM:
            if (inputLen < sizeof(ULONG_PTR) || outputLen < sizeof(ULONG)) {
                status = STATUS_BUFFER_TOO_SMALL;
                break;
            }
            addr = *(PULONG_PTR)inputBuffer;
            value = *(PULONG)addr; // 任意读
            *(PULONG)outputBuffer = value;
            break;
        case IOCTL_WRITE_MEM:
            if (inputLen < sizeof(ULONG_PTR) + sizeof(ULONG)) {
                status = STATUS_BUFFER_TOO_SMALL;
                break;
            }
            addr = *(PULONG_PTR)inputBuffer;
            value = *(PULONG)((PUCHAR)inputBuffer + sizeof(ULONG_PTR));
            *(PULONG)addr = value; // 任意写
            break;
        default:
            status = STATUS_INVALID_DEVICE_REQUEST;
    }
    Irp->IoStatus.Status = status;
    Irp->IoStatus.Information = (status == STATUS_SUCCESS) ? outputLen : 0;
    IoCompleteRequest(Irp, IO_NO_INCREMENT);
    return status;
}

